#include <stdio.h>

int main() {
    FILE *fp = fopen("data.txt", "w");
    if (fp == NULL) {
        printf("Error opening file\n");
        return 1;
    }
    printf("File opened successfully\n");
    fclose(fp);
    return 0;
}

#include <stdio.h>

int main() {
    FILE *fp = fopen("data.txt", "w");
    if (fp != NULL) {
        fprintf(fp, "Hello, File Handling! %d\n", 2023);
        fclose(fp);
    }
    return 0;
}

#include <stdio.h>

int main() {
    char buffer[100];
    FILE *fp = fopen("data.txt", "r");
    if (fp != NULL) {
        while (fgets(buffer, 100, fp) != NULL) {
            printf("%s", buffer);
        }
        fclose(fp);
    }
    return 0;
}

#include <stdio.h>

int main() {
    FILE *fp = fopen("chars.txt", "w");
    if (fp != NULL) {
        fputc('A', fp);
        fputc('B', fp);
        fputc('C', fp);
        fclose(fp);
    }
    return 0;
}

#include <stdio.h>

int main() {
    char name[20];
    int score;
    FILE *fp = fopen("score.txt", "r");
    if (fp != NULL) {
        fscanf(fp, "%s %d", name, &score);
        printf("Name: %s, Score: %d\n", name, score);
        fclose(fp);
    }
    return 0;
}

#include <stdio.h>

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    FILE *fp = fopen("numbers.bin", "wb"); // wb for write binary
    if (fp != NULL) {
        fwrite(arr, sizeof(int), 5, fp);
        fclose(fp);
    }
    return 0;
}

#include <stdio.h>

int main() {
    int readArr[5];
    FILE *fp = fopen("numbers.bin", "rb");
    if (fp != NULL) {
        fread(readArr, sizeof(int), 5, fp);
        printf("First element: %d\n", readArr[0]);
        fclose(fp);
    }
    return 0;
}
